const items = $input.all();
let msg = '⏰ *VENCIMIENTOS PROXIMOS*\n\n';
items.forEach(item => {
  const v = item.json;
  const diasTexto = v.dias_restantes === 0 ? 'HOY' : v.dias_restantes === 1 ? 'mañana' : `en ${v.dias_restantes} dias`;
  const monto = v.moneda === 'USD' ? `U$D ${v.monto}` : `$${Math.round(v.monto).toLocaleString('es-AR')}`;
  msg += `${v.icono} ${v.concepto} — ${monto} — ${diasTexto}\n`;
});
return { msg };

const d = $input.first().json;
const fmt = n => Math.round(n || 0).toLocaleString('es-AR');
const pct = (g, t) => t > 0 ? Math.round(g / t * 100) : 0;

let msg = `📊 *RESUMEN SEMANAL*\n\n`;
msg += `💵 U$D ${d.ingreso_usd || 0} → $${fmt(d.ingreso_ars)} (TC: $${fmt(d.tipo_cambio)})\n\n`;
msg += `🏠 Necesidades  $${fmt(d.gastado_necesidades)} / $${fmt(d.presupuesto_necesidades)} — ${pct(d.gastado_necesidades, d.presupuesto_necesidades)}%\n`;
msg += `🎯 Deseos       $${fmt(d.gastado_deseos)} / $${fmt(d.presupuesto_deseos)} — ${pct(d.gastado_deseos, d.presupuesto_deseos)}%\n`;
msg += `💳 Compromisos TC: $${fmt(d.compromisos_tc)}\n\n`;
msg += `✅ Disponible: $${fmt(d.disponible_para_gastar)}`;
return { msg };

const cierre = $('Cierre mensual BD').first().json;
